@triton.jit
def mul_relu_kernel(
    input_ptr, other_ptr, output_ptr,
    input_size,
    inplace: tl.constexpr,
    other_is_scalar: tl.constexpr,
    BLOCK_SIZE: tl.constexpr
):
    pid = tl.program_id(0)
    block_start = pid * BLOCK_SIZE
    offsets = block_start + tl.arange(0, BLOCK_SIZE)
    mask = offsets < input_size

    input = tl.load(input_ptr + offsets, mask=mask)

    if other_is_scalar:
        other = other_ptr[0]
        result = input * other
    else:
        other = tl.load(other_ptr + offsets, mask=mask)
        result = input * other

    relu_result = tl.where(result > 0, result, 0)

    if inplace:
        tl.store(input_ptr + offsets, relu_result, mask=mask)
    else:
        tl.store(output_ptr + offsets, relu_result, mask=mask)

def mul_relu(input, other, inplace=False, out=None) -> torch.Tensor:
