        raise ValueError("input must be of type float32")

    if not isinstance(other, torch.Tensor) and not isinstance(other, (int, float)):
        raise TypeError("other must be a torch.Tensor, int, or float")

    if isinstance(other, torch.Tensor) and other.dtype != torch.float32:
        raise ValueError("other must be of type float32")

    if input.shape != other.shape and not isinstance(other, (int, float)):
        raise ValueError("input and other must have the same shape when other is a tensor")

    if inplace and not input.requires_grad:
        output = input
    elif out is not None:
        output = out
    else:
        output = torch.empty_like(input, dtype=torch.float32)

    if input.numel() == 0:
        return output

    input_ptr = input.data_ptr()
    other_ptr = other.data_ptr() if isinstance(other, torch.Tensor) else other
    output_ptr = output.data_ptr()

    if isinstance(other, torch.Tensor):
        other_is_scalar = False
    else:
        other_is_scalar = True
        other_ptr = torch.tensor([other], dtype=torch.float32).data_ptr()

    BLOCK_SIZE = 1024
    grid_size = (input.numel() + BLOCK_SIZE - 1) // BLOCK_SIZE

    mul_relu_kernel[grid_size](
        input_ptr, other_ptr, output_ptr,
        input.numel(),
        inplace,
        other_is_scalar,
        BLOCK_SIZE
    )

    return output

