@triton.jit
def _qr_kernel(
    A_ptr, Q_ptr, R_ptr,
    m, n, batch_size,
    stride_am, stride_an,
    stride_qm, stride_qn,
    stride_rm, stride_rn,
    BLOCK_SIZE_M: tl.constexpr,
    BLOCK_SIZE_N: tl.constexpr,
    BLOCK_SIZE_K: tl.constexpr,
    dtype: tl.constexpr
):
    batch_idx = tl.program_id(0)
    m_idx = tl.program_id(1)
    n_idx = tl.program_id(2)

    # Load matrix A
    a_block = tl.zeros((BLOCK_SIZE_M, BLOCK_SIZE_N), dtype=dtype)
    for i in range(0, BLOCK_SIZE_M):
        for j in range(0, BLOCK_SIZE_N):
            if m_idx * BLOCK_SIZE_M + i < m and n_idx * BLOCK_SIZE_N + j < n:
                a_block[i, j] = tl.load(
                    A_ptr + batch_idx * stride_am + (m_idx * BLOCK_SIZE_M + i) * stride_an + (n_idx * BLOCK_SIZE_N + j)
                )

    # Initialize Q and R
    q_block = tl.zeros((BLOCK_SIZE_M, BLOCK_SIZE_M), dtype=dtype)
    r_block = tl.zeros((BLOCK_SIZE_M, BLOCK_SIZE_N), dtype=dtype)

    # Initialize Q as identity matrix
    for i in range(0, BLOCK_SIZE_M):
        if i < m:
            q_block[i, i] = 1.0

    # Copy A to R
    for i in range(0, BLOCK_SIZE_M):
        for j in range(0, BLOCK_SIZE_N):
            if i < m and j < n:
                r_block[i, j] = a_block[i, j]

    # Givens rotations for QR decomposition
    for k in range(0, min(BLOCK_SIZE_M, BLOCK_SIZE_N)):
        # Compute Givens rotation
        if k < BLOCK_SIZE_M and k < BLOCK_SIZE_N:
            r_kk = r_block[k, k]
            if abs(r_kk) > 1e-12:
                # Compute cosine and sine
                r_kk_abs = abs(r_kk)
                r_kk_sign = 1.0 if r_kk >= 0 else -1.0
                c = r_kk_abs / (r_kk_abs + abs(r_block[k+1, k]))
                s = r_kk_sign * r_block[k+1, k] / (r_kk_abs + abs(r_block[k+1, k]))

                # Apply Givens rotation to R
                for j in range(k, BLOCK_SIZE_N):
                    temp = r_block[k, j]
                    r_block[k, j] = c * temp + s * r_block[k+1, j]
                    r_block[k+1, j] = -s * temp + c * r_block[k+1, j]

                # Apply Givens rotation to Q
                for i in range(0, BLOCK_SIZE_M):
                    temp = q_block[i, k]
                    q_block[i, k] = c * temp + s * q_block[i, k+1]
                    q_block[i, k+1] = -s * temp + c * q_block[i, k+1]

    # Store results
    for i in range(0, BLOCK_SIZE_M):
        for j in range(0, BLOCK_SIZE_M):
            if i < m and j < m:
                tl.store(
                    Q_ptr + batch_idx * stride_qm + (m_idx * BLOCK_SIZE_M + i) * stride_qn + (n_idx * BLOCK_SIZE_M + j),
                    q_block[i, j]
                )

    for i in range(0, BLOCK_SIZE_M):
        for j in range(0, BLOCK_SIZE_N):
            if i < m and j < n:
                tl.store(
                    R_ptr + batch_idx * stride_rm + (m_idx * BLOCK_SIZE_M + i) * stride_rn + (n_idx * BLOCK_SIZE_N + j),
                    r_block[i, j]
                )

