            elif i > j:
                tl.store(L_base + i * stride_lm + j * stride_ln, tl.load(A_base + i * stride_am + j * stride_an))
            else:
                tl.store(U_base + i * stride_um + j * stride_un, tl.load(A_base + i * stride_am + j * stride_an))

