    for i in range(BLOCK_SIZE - 1, -1, -1):
        sum_val = 0.0
        for j in range(i + 1, BLOCK_SIZE):
            sum_val += U[i * stride_u + j] * b[j * stride_b]
        b[i * stride_b] = (b[i * stride_b] - sum_val) / U[i * stride_u + i]

